import boto3
import json

sqs = boto3.resource('sqs')
queue_url = 'https://sqs.us-east-1.amazonaws.com/123456789012/my_queue'

def process_message(message):
    message_body = json.loads(message['Body'])
    
    if 'type' in message_body:
        if message_body['type'] == 'job':
            # Process job message
            print(f"Processing job {message_body['id']}")
            # Add your job processing logic here
        elif message_body['type'] == 'task':
            # Process task message
            print(f"Processing task {message_body['id']}")
            # Add your task processing logic here
    else:
        print("Invalid message type")

def receive_message():
    response = sqs.receive_message(
        QueueUrl=queue_url,
        MaxNumberOfMessages=10,
        WaitTimeSeconds=20
    )
    
    if 'Messages' in response:
        for message in response['Messages']:
            process_message(message)
            # Delete the processed message from SQS
            sqs.delete_message(QueueUrl=queue_url, ReceiptHandle=message['ReceiptHandle'])
            
def worker():
    while True:
        receive_message()
        
if __name__ == '__main__':
    worker()